  "title": "Burmese Snacks Cooking Course",
  "description": "A comprehensive course designed for beginners to learn the art of cooking traditional Burmese snacks, with a focus on mohinga.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Burmese Cuisine",
      "description": "Explore the rich history and cultural significance of Burmese snacks, with an overview of common ingredients and cooking techniques."
    },
    {
      "id": "module2",
      "title": "Ingredients and Preparation for Mohinga",
      "description": "Learn about the essential ingredients for making mohinga, including fish, noodles, and spices, along with preparation techniques."
    },
    {
      "id": "module3",
      "title": "Cooking Mohinga Step-by-Step",
      "description": "Follow a guided cooking session to prepare mohinga from scratch, including tips for achieving the perfect broth and noodle texture."
    },
    {
      "id": "module4",
      "title": "Serving and Enjoying Mohinga",
      "description": "Discover traditional serving methods for mohinga, garnishing techniques, and pairing suggestions to enhance your dining experience."
    }
  ]
